""""
EOF v1 validation code - Exported from evmone unit tests
"""

import pytest
from ethereum_test_tools import EOFTestFiller, EOFException, Opcodes as Op
from ethereum_test_tools.eof.v1 import Container, Section

REFERENCE_SPEC_GIT_PATH = "EIPS/eip-3540.md"
REFERENCE_SPEC_VERSION = "12ca2f0bd2f7380100e154aaaa0995c46cbb2710"

# Container containing 256 code sections, section index 2 is unreachable
unreachable_code_sections_6 = Container(
    name="EOFV1_0007",
    sections=[
        Section.Code(code=Op.JUMPF[1]),
        Section.Code(code=Op.JUMPF[1]),
    ] + [Section.Code(code=Op.JUMPF[i+1]) for i in range(2, 255)] 
      + [Section.Code(code=Op.NOP * 3 + Op.STOP)]
)

# Container containing 256 code sections, section index 255 is unreachable
unreachable_code_sections_7 = Container(
    name="EOFV1_0007",
    sections=[
        Section.Code(code=Op.JUMPF[1]),
    ] + [Section.Code(code=Op.JUMPF[i+1]) for i in range(1, 254)] 
      + [Section.Code(code=Op.JUMPF[254])]
      + [Section.Code(code=Op.NOP * 3 + Op.STOP)]
)


@pytest.mark.parametrize(
    "eof_code,expected_hex_bytecode,exception",
    [
        pytest.param(
              Container(
                name = 'EOFV1_0001',
                sections = [
                    Section.Code(code=Op.INVALID, max_stack_height=0),
                    Section.Code(code=Op.INVALID, max_stack_height=0),
                    ],
              )
              ,
              "ef000101000802000200010001040000000080000000800000fefe",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_0"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0002',
                sections = [
                    Section.Code(code=Op.CALLF[1] + Op.STOP, max_stack_height=0),
                    Section.Code(code=Op.NOP + Op.RETF, code_outputs=0, max_stack_height=0),
                    Section.Code(code=Op.INVALID, max_stack_height=0),
                    ],
              )
              ,
              "ef000101000c02000300040002000104000000008000000000000000800000e30001005be4fe",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_1"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0003',
                sections = [
                    Section.Code(code=Op.CALLF[2] + Op.STOP, max_stack_height=0),
                    Section.Code(code=Op.INVALID, max_stack_height=0),
                    Section.Code(code=Op.NOP + Op.RETF, code_outputs=0, max_stack_height=0),
                    ],
              )
              ,
              "ef000101000c02000300040001000204000000008000000080000000000000e3000200fe5be4",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_2"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0004',
                sections = [
                    Section.Code(code=Op.CALLF[3] + Op.STOP, max_stack_height=0),
                    Section.Code(code=Op.INVALID, max_stack_height=0),
                    Section.Code(code=Op.NOP + Op.RETF, code_outputs=0, max_stack_height=0),
                    Section.Code(code=Op.CALLF[2] + Op.RETF, code_outputs=0, max_stack_height=0),
                    ],
              )
              ,
              "ef000101001002000400040001000200040400000000800000008000000000000000000000e3000300fe5be4e30002e4",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_3"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0005',
                sections = [
                    Section.Code(code=Op.JUMPF[0], max_stack_height=0),
                    Section.Code(code=Op.JUMPF[1], max_stack_height=0),
                    ],
              )
              ,
              "ef000101000802000200030003040000000080000000800000e50000e50001",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_4"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0006',
                sections = [
                    Section.Code(code=Op.JUMPF[1], max_stack_height=0),
                    Section.Code(code=Op.STOP, max_stack_height=0),
                    Section.Code(code=Op.NOP + Op.RETF, code_outputs=0, max_stack_height=0),
                    ],
              )
              ,
              "ef000101000c02000300030001000204000000008000000080000000000000e50001005be4",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_5"
        ),
        pytest.param(
              unreachable_code_sections_6,
              "",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_6"
        ),
        pytest.param(
              unreachable_code_sections_7,
              "",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_7"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0009',
                sections = [
                    Section.Code(code=Op.JUMPF[1], max_stack_height=0),
                    Section.Code(code=Op.JUMPF[1], max_stack_height=0),
                    Section.Code(code=Op.JUMPF[2], max_stack_height=0),
                    ],
              )
              ,
              "ef000101000c02000300030003000304000000008000000080000000800000e50001e50001e50002",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_8"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0010',
                sections = [
                    Section.Code(code=Op.JUMPF[1], max_stack_height=0),
                    Section.Code(code=Op.JUMPF[2], max_stack_height=0),
                    Section.Code(code=Op.INVALID, max_stack_height=0),
                    Section.Code(code=Op.JUMPF[4], max_stack_height=0),
                    Section.Code(code=Op.JUMPF[3], max_stack_height=0),
                    ],
              )
              ,
              "ef000101001402000500030003000100030003040000000080000000800000008000000080000000800000e50001e50002fee50004e50003",
              EOFException.UNREACHABLE_CODE_SECTIONS,
              id="unreachable_code_sections_9"
        ),
        
    ]
)

def test_example_valid_invalid(
    eof_test: EOFTestFiller,
    eof_code: Container,
    expected_hex_bytecode: str,
    exception: EOFException | None,
):
    """
    Verify eof container construction and exception
    """
    assert bytes(eof_code) == bytes.fromhex(expected_hex_bytecode)

    eof_test(
        data=eof_code,
        expect_exception=exception,
    )
